// 从HTTP Request响应中提取obj_token作为app_token
const httpResponse = $input.last().json;

return {
  app_token: httpResponse.body?.data?.node?.obj_token || null,
  table_id: $('判断是否Wiki类型').first().json.table_id,
};

// base类型直接返回，app_token已经在Code节点1中解析好了
return {
  app_token: $json.app_token,
  table_id: $json.table_id
};

const item = $input.item;

// 获取 binary 数据
const binaryPropertyName = Object.keys(item.binary || {})[0];
const binaryData = item.binary?.[binaryPropertyName];

let actualFileSize = null;

if (binaryData) {
  console.log('Binary 对象的所有属性:', JSON.stringify(Object.keys(binaryData)));
  console.log('Binary 完整对象:', JSON.stringify(binaryData, null, 2));

  // 在 n8n 中，binary 数据可能有 id 属性，需要通过特殊方式获取
  // 尝试使用 $binary 辅助函数
  try {
    const binaryBuffer = await this.helpers.getBinaryDataBuffer(0, binaryPropertyName);
    actualFileSize = binaryBuffer.length;
    console.log('通过 getBinaryDataBuffer 获取的大小:', actualFileSize);
  } catch (error) {
    console.log('getBinaryDataBuffer 失败:', error.message);

    // 备用方案：尝试直接读取
    if (binaryData.data) {
      if (Buffer.isBuffer(binaryData.data)) {
        actualFileSize = binaryData.data.length;
      } else if (typeof binaryData.data === 'string') {
        // 清理 base64 字符串
        const base64Clean = binaryData.data
          .replace(/^data:.*?;base64,/, '')
          .replace(/\s/g, '');

        actualFileSize = Buffer.from(base64Clean, 'base64').length;
      }
    }
  }
}

console.log('最终文件大小:', actualFileSize, '字节');
console.log('最终文件大小:', actualFileSize ? (actualFileSize / 1024).toFixed(2) : 'N/A', 'KB');

return {
  json: {
    ...item.json,
    fileSizeBytes: actualFileSize,
    fileSizeKB: actualFileSize ? (actualFileSize / 1024).toFixed(2) : null,
    fileName: binaryData?.fileName || 'unknown',
    mimeType: binaryData?.mimeType || 'unknown'
  },
  binary: item.binary
};

// 获取输入的URL
const url = $('凭证配置器').first().json.bitableURL

const data = {
  app_token: null,
  table_id: null,
  view_id: null,
  is_wiki: false,
  wiki_token: null
};

// 解析 app_token (base类型)
let matches = url.match(/\/base\/(.*?)(\?|$)/);
if (matches) {
  data.app_token = matches[1];
} else {
  // 解析 wiki 类型
  matches = url.match(/\/wiki\/(.*?)(\?|$)/);
  if (matches) {
    data.is_wiki = true;
    data.wiki_token = matches[1];
  }
}

// 解析 table_id
matches = url.match(/table=(.*?)(&|$)/);
if (matches) {
  data.table_id = matches[1];
}

// 解析 view_id
matches = url.match(/view=(.*?)(&|$)/);
if (matches) {
  data.view_id = matches[1];
}

return data;
